-- Engens Träd — Strategidokument + invändningar + uppdaterad brand-profil
-- Bygger ovanpå tidigare onboarding-migration

DO $$
DECLARE
  v_client_id uuid := 'e9e9e9e9-7e2d-4a2b-9c1f-e1ce115da001'::uuid;
BEGIN
  -- 1. UPPDATERA BRAND-PROFIL med arketype + skärpta kundlöften
  UPDATE hm_brand_profile SET
    tagline = 'Trygg trädfällning utan drama — i Roslagen och norra Stockholm',
    usp = E'Primärt löfte: Du får trädet borttaget säkert, snyggt och utan stress.\nSekundärt löfte: Du slipper gissa, oroa dig eller ta risker själv.\n\nKommersiell vinkel: Vi gör riskfyllda, svåra och uppskjutna trädproblem enkla, säkra och lugna för kunden. Arketype = trygg expert + lokal problemlösare. En blandning av den metodiska yrkespersonen, den hjälpsamma grannen, den säkra hantverkaren och den lugna problemlösaren. Rickards roll i kundens huvud: "den lugna experten som ser riskerna innan kunden gör det".',
    brand_story = E'Engens Träd är Rickards företag. Rickard är central i varumärket och ska aldrig döljas bakom företagsnamnet — han ÄR förtroendet. Lokal, praktisk, lugn, kunnig och jordnära. Det som avgör är att kunden känner: "Honom vågar jag släppa in på tomten."\n\nEngens Träd kommunicerar inte som ett trädfällningsföretag. Engens Träd kommunicerar som Rickard: en trygg, lokal expert som kommer ut, tittar på trädet, säger vad som är rimligt och löser jobbet säkert. Det är där förtroendet ligger. Det är där affären finns.\n\nMedlem i Svenska Trädföreningen. RUT-avdrag gäller. 5/5 Google, 100% rekommendation Facebook.',
    tone_rules = E'Rickards röst: Rakt. Varmt. Sakligt. Lite vardagligt. Aldrig överdrivet.\n\nTonen ska VARA: trygg, mänsklig, lokal, konkret, lugn, erfaren, lite personlig, problemlösande.\nTonen ska INTE vara: branschjargong, "vi är bäst", aggressiv säljton, polerad reklambyråkänsla, långa tekniska förklaringar, humor i riskinlägg.\n\nNyckelord att återkomma till (variera): säkert, lugnt, kontrollerat, nära hus, riskträd, tomt, trygghet, bedömning, Roslagen, Åkersberga, utan drama, rent efteråt, bit för bit, rätt metod, innan det blir akut.\n\nAnvänd kundens egna formuleringar: "det skymmer solen", "det känns lite läskigt", "det står för nära huset", "vi har pratat om det i flera år", "vi vill bara få det gjort", "vi vill kunna använda gräsmattan".\n\nKommunicera som Rickard — inte som ett företag. Han ska inte låta som en säljare. Han ska låta som någon som vet vad han gör.',
    differentiators = E'Det Engens äger:\n- Lokal trygghet & personligt förtroende (Rickard som ansikte)\n- Riskträd nära hus, el, väg, lekytor\n- Små och trånga ytor — sektionsfällning\n- Rent, snyggt och ordnat efteråt\n- Kundens lugn före, under, efter\n\nDet Engens INTE tävlar om: billigast pris, störst maskinpark, mest företagsmässig fasad, "vi gör allt för alla".\n\nEnkel konkurrensfördel: Många kan fälla ett träd. Färre kan få kunden att känna sig lugn före, under och efter jobbet.',
    pricing_notes = E'Priset beror på läge, storlek, risk och vad kunden vill ha hjälp med efteråt. RUT halverar arbetskostnaden direkt på fakturan upp till takbeloppet. En bild räcker ofta för en första uppskattning.\n\nVanliga invändningar att möta:\n1. "Det är inte så bråttom" → trädet avgör inte tidpunkten, väder och vind gör det\n2. "Jag kan göra det själv" → öppna ytor OK, nära hus blir marginalerna små\n3. "Det blir säkert dyrt" → RUT + bild för uppskattning\n4. "Måste hela trädet bort?" → ibland räcker beskärning, bedömning först',
    updated_at = now()
  WHERE client_id = v_client_id;

  -- 2. STRATEGIDOKUMENT som master-asset (flödar till alla AI via getProfileAsMarkdown)
  DELETE FROM client_assets WHERE client_id = v_client_id AND category = 'strategy_doc';

  INSERT INTO client_assets (client_id, asset_type, category, title, body, person_name, person_label, tags, voice_score, status, ai_summary) VALUES
  (v_client_id, 'document', 'strategy_doc',
   'Strategidokument — djupanalys, persona och innehållsstrategi',
   E'# Engens Träd — Strategidokument (master)\n\n## Kärnslutsats\nEngens Träd bör positioneras som den trygga, lokala trädexperten för villaägare som har ett trädproblem de inte vill, kan eller vågar hantera själva. Starkaste kommersiella vinkeln: "Vi gör riskfyllda, svåra och uppskjutna trädproblem enkla, säkra och lugna för kunden." Rickard är central — han ska inte döljas bakom företagsnamnet.\n\n## Varumärkespersona\n- Arketype: trygg expert + lokal problemlösare\n- Blandning av: den metodiska yrkespersonen, den hjälpsamma grannen, den säkra hantverkaren, den lugna problemlösaren\n- Rickards roll i kundens huvud: "den lugna experten som ser riskerna innan kunden gör det"\n- Primärt löfte: Du får trädet borttaget säkert, snyggt och utan stress\n- Sekundärt löfte: Du slipper gissa, oroa dig eller ta risker själv\n\n## Positionering (4 varianter)\n- Huvudpositionering: Engens Träd är den trygga trädfällaren i Roslagen och norra Stockholm för villaägare som vill ha svåra trädjobb utförda säkert, snyggt och personligt.\n- Kort: Trygg trädfällning nära hus, tomt och människor.\n- Personlig: Rickard på Engens Träd hjälper villaägare i Roslagen att ta ner träd säkert, lugnt och utan drama.\n- Säljande: Har du ett träd som känns fel, står för nära huset eller skymmer hela tomten? Rickard hjälper dig bedöma, planera och ta ner det säkert.\n\n## Vad marknaden faktiskt köper\nLugn · säkerhet · kontroll · en tydlig plan · någon som tar ansvar · en tomt som känns trygg igen · att slippa göra fel själv · att slippa skador på hus/bil/grannar/familj · att arbetet blir färdigt och undanplockat. Kommunikationen ska fokusera på konsekvens, trygghet och upplevelse — inte motorsåg, höjd, teknik.\n\n## Primär målgrupp: Villaägare 35-70 år i Roslagen/norra Stockholm\nÅkersberga, Täby, Vallentuna, Vaxholm, Norrtälje, Ljusterö, Danderyd, Upplands Väsby.\n\n### Typiska situationer\n- Träd lutar lite mer än tidigare\n- Träd står nära hus, garage, förråd, altan\n- Grenar över tak/fasad\n- Träd skymmer sol\n- Kunden vill bygga, öppna upp, skapa mer yta\n- Storm/vinter/snö har skadat trädet\n- Kunden har skjutit upp beslutet länge\n- Kunden vet inte om trädet är sjukt, farligt eller bara "fult"\n\n### Psykologiskt tillstånd före köp\n- "Jag borde ta tag i det där."\n- "Det kanske klarar sig ett år till."\n- "Tänk om det faller fel."\n- "Jag vet inte vem jag ska ringa."\n- "Jag vill inte bli lurad."\n- "Jag vill ha någon som kan titta och säga vad som är rimligt."\n\n### Vad kunden behöver höra\n- Du behöver inte veta exakt vad som ska göras.\n- Rickard kan komma ut och bedöma trädet.\n- Det finns säkra sätt att ta ner träd även på trånga ytor.\n- Du får hjälp med plan, fällning, städning, bortforsling och RUT.\n- Hellre kolla en gång för mycket än vänta tills akut.\n\n## Sekundära målgrupper\n- BRF: trygghet, ansvar, dokumenterad metodik. Ton: strukturerad, saklig, riskreducerande.\n- Företag/fastighetsägare: effektivitet, tydlig offert, låg störning, säkerhet.\n- Sommarhusägare (Ljusterö/skärgård): lösa snabbt när man är på plats.\n\n## Rickards röst\nRakt. Varmt. Sakligt. Lite vardagligt. Aldrig överdrivet.\n\nExempel:\n- "Det där trädet ser kanske lugnt ut. Men när stammen lutar, marken rör sig eller grenarna börjar dö, då är det värt att kolla upp innan det blir ett problem."\n- "Alla träd behöver inte fällas. Men de träd som står nära hus, el, väg eller lekytor behöver bedömas med rätt ögon."\n- "Vi tar ner det kontrollerat, bit för bit, och lämnar tomten snygg efteråt."\n\n## 5 innehållspelare\n1. **Riskträd och trygghet** (TOFU): risktecken, säsong, lutning, döda grenar, stormrisk\n2. **Före/efter och resultat** (TOFU/MOFU): visuell bekräftelse, mörk → ljus tomt\n3. **Rickard förklarar** (MOFU): expertstatus utan stelhet — "så tänker jag innan jag tar ner ett träd"\n4. **Kundtrygghet och social proof** (MOFU): kundomdömen, case, "kunden var orolig"\n5. **Praktiska beslut** (BOFU): RUT, offert, "skicka bild", vad som ingår\n\n## Funnel: 65-70% TOFU / 25-30% MOFU / 5% BOFU\n4 av 5 inlägg ska inte kännas som säljinlägg. Det femte gör jobbet.\n\n## Veckomix\n- Mån: Analytical / C / TOFU — utbildande, risktecken\n- Tis: Analytical / D / MOFU — så går arbetet till\n- Ons: Aspirational / I / TOFU — före/efter\n- Tor: Aspirational / S / TOFU — trygghet, kundkänsla\n- Fre: Actionable / D / BOFU eller MOFU — skicka bild, RUT, boka\n- Lör: Actionable / C / TOFU — checklista\n- Sön: Authentic / S/I / TOFU — personligt från Rickard\n\n## 5 återkommande serier\n1. **Rickard kollar trädet** — kort video/bild: visa träd → vad Rickard tittar på → 1-2 tecken → mjuk CTA\n2. **Nära huset-jobb** — före/efter eller video: problem → sektionsfällning → trygg tomt\n3. **Trädet som tog över tomten** — aspirerande före/efter: skugga/oro → träd ner → ljus & yta\n4. **Frågor Rickard ofta får** — text/bild/video: får jag fälla själv, RUT, stubbe, nära huset, pris\n5. **Efter jobbet** — bild/video på städad tomt: ordning lika viktigt som fällning\n\n## 5 vanliga invändningar + svar\n1. "Det är nog inte så bråttom." → "Det kan stämma. Men om trädet lutar, har döda grenar eller står nära hus är det klokt att få det bedömt innan väder och vind avgör åt dig."\n2. "Jag kanske kan göra det själv." → "På öppna ytor kan vissa träd vara enkla. Men nära hus, el, väg, andra träd eller byggnader blir marginalerna små. Då är planeringen viktigare än själva sågningen."\n3. "Det blir säkert dyrt." → "Priset beror på läge, storlek, risk och vad du vill ha hjälp med efteråt. RUT kan sänka arbetskostnaden och en bild räcker ofta för en första uppskattning."\n4. "Måste hela trädet bort?" → "Inte alltid. Ibland räcker beskärning. Därför börjar vi med att bedöma trädet och platsen innan vi rekommenderar åtgärd."\n\n## DISC-strategi\n- D (Driver): "Vi löser det säkert. Du får besked snabbt." Format: före/efter, tydlig CTA, problem→lösning\n- I (Influence): "Titta vilken skillnad det blev. Tomten fick ljus igen." Format: videos, personliga inlägg, bakom kulisserna\n- S (Steadiness): "Vi går igenom allt innan. Vi tar det steg för steg." Format: process, kundomdömen, trygg rådgivning\n- C (Compliance): "Vi bedömer lutning, skick, placering, riskzon. RUT gäller flera delar." Format: checklistor, utbildande, förklaringar\n\n## Bild- och videostrategi\nPrioritera: Rickard i arbete · träd nära hus · sektionsfällning · före/efter · ren tomt efteråt · kundens problemvinkel · utrustning i användning · ris/kaos som blir ordning · lokala miljöer.\nUndvik: generiska stockbilder · enbart motorsåg-närbilder · för mycket höjdklättring utan kundnytta · bilder utan sammanhang.\nVideoformat: (1) hook på skärm "Det här trädet stod 3 m från huset" → (2) problem → (3) arbetsmoment → (4) resultat → (5) "Osäker på ett träd? Skicka en bild."\n\n## Profiltexter\n- Facebook bio: "Säker trädfällning, sektionsfällning och trädgårdsarbete i Åkersberga, Roslagen och norra Stockholm. Rickard på Engens Träd hjälper dig med trygga trädjobb nära hus, tomt och människor."\n- Kort tagline: "Trygg trädfällning utan drama."\n- Lokal tagline: "Din lokala trädfällare i Roslagen och norra Stockholm."\n\n## Kundresa\n1. Omedveten — ser trädet varje dag. Innehåll: risktecken, säsong, igenkänning.\n2. Problemmedveten — börjar känna oro. Innehåll: "så vet du om trädet behöver bedömas".\n3. Lösningsmedveten — förstår att hjälp behövs. Innehåll: sektionsfällning, process, hembesök.\n4. Leverantörsval — jämför alternativ. Innehåll: kundcase, recensioner, Rickard på bild, före/efter, rent efteråt.\n5. Kontakt — låg tröskel. Innehåll: skicka bild, ring, offert, områden, RUT.\n\n## Strategisk kärna (alltid)\nMer Rickard. Mer riskmedvetenhet. Mer före/efter. Mer trygg process. Mer lokal förankring. Mindre generell företagstext.\n\nKunden ska känna: "Han vet vad han gör." · "Han verkar lugn och ordentlig." · "Det här känns tryggt." · "Jag behöver inte lösa allt själv." · "Det blir snyggt efteråt."',
   'Rickard Engström', 'strategy_master',
   ARRAY['strategy','persona','positionering','disc','funnel','master_doc'],
   9.5, 'active',
   'Master-strategidokument för Engens Träd. Driver all AI-output via universal voice flow (getProfileAsMarkdown). Innehåller arketype, primärt+sekundärt kundlöfte, 4 positioneringsvarianter, 5 innehållspelare, veckomix, 5 serier, 4 invändningar+svar, DISC-strategi, bild/video, kundresa, profiltexter.');

  -- 3. INVÄNDNINGAR som winning examples (lär AI:n hantera dem i Rickards röst)
  INSERT INTO client_assets (client_id, asset_type, category, title, body, person_name, person_label, tags, voice_score, status) VALUES
  (v_client_id, 'post', 'winning_example',
   E'Invändning — "Det är inte så bråttom"',
   E'"Det är nog inte så bråttom."\n\nDet kan stämma. Men om trädet lutar, har döda grenar eller står nära hus är det klokt att få det bedömt innan väder och vind avgör åt dig.\n\nEn första bedömning kostar inget. Och du får ett rakt svar på om det behöver göras nu, nästa år, eller inte alls.\n\nSkicka en bild på trädet och var det står — så återkommer vi.',
   'Rickard Engström','engens_seed',ARRAY['objection','bråttom','mjuk_cta'],9.5,'active'),

  (v_client_id, 'post', 'winning_example',
   E'Invändning — "Jag kan göra det själv"',
   E'"Jag kanske kan göra det själv."\n\nPå öppna ytor kan vissa träd vara enkla. Men nära hus, el, väg, andra träd eller byggnader blir marginalerna små.\n\nDå är planeringen viktigare än själva sågningen. Det är där jobbet egentligen ligger — i att veta var trädet ska landa innan motorsågen ens startar.\n\nOsäker på om ditt träd är ett DIY-jobb eller ett "ring någon"-jobb? Skicka en bild, så säger vi rakt ut.',
   'Rickard Engström','engens_seed',ARRAY['objection','diy','planering'],9.5,'active'),

  (v_client_id, 'post', 'winning_example',
   E'Invändning — "Det blir säkert dyrt"',
   E'"Det blir säkert dyrt."\n\nPriset beror på fyra saker: läge, storlek, risk och vad du vill ha hjälp med efteråt.\n\nRUT-avdraget sänker arbetskostnaden direkt på fakturan — upp till takbeloppet. Det betyder ofta att jobbet hamnar någonstans helt annat än du tror.\n\nEn bild räcker ofta för en första uppskattning. Då vet du om det är värt att gå vidare.',
   'Rickard Engström','engens_seed',ARRAY['objection','pris','rut'],9.5,'active'),

  (v_client_id, 'post', 'winning_example',
   E'Invändning — "Måste hela trädet bort?"',
   E'"Måste hela trädet bort?"\n\nInte alltid. Ibland räcker beskärning. Ibland är det bara en gren eller en topp som ska tas.\n\nDärför börjar vi med att bedöma trädet och platsen innan vi rekommenderar åtgärd. Min uppgift är att säga vad som är rimligt — inte att sälja in största möjliga jobb.\n\nVissa träd ska inte bort. Andra behöver tas på allvar. Vi börjar med att titta.',
   'Rickard Engström','engens_seed',ARRAY['objection','beskärning','bedömning'],9.5,'active');

END $$;

SELECT
  (SELECT count(*) FROM client_assets WHERE client_id='e9e9e9e9-7e2d-4a2b-9c1f-e1ce115da001'::uuid AND category='winning_example') as winning_examples,
  (SELECT count(*) FROM client_assets WHERE client_id='e9e9e9e9-7e2d-4a2b-9c1f-e1ce115da001'::uuid AND category='strategy_doc') as strategy_docs,
  (SELECT tagline FROM hm_brand_profile WHERE client_id='e9e9e9e9-7e2d-4a2b-9c1f-e1ce115da001'::uuid) as tagline;
